function SleepList({
    sleepLogs,
    calcSleepMinutes,
    formatMinutes,
    deleteRecords
}) {
    return(
        <div>
            <h2>記録一覧</h2>
            {sleepLogs.map((sleepLog, index) => {
                const sleepMinutes = calcSleepMinutes(sleepLog.bedTime, sleepLog.wakeUpTime);
                return(
                    <div key={index}>
                        {sleepLog.sleepType === "ohirune" ? "お昼寝" : "夜の睡眠"}　
                        {sleepLog.bedTime} → {sleepLog.wakeUpTime}
                        （{formatMinutes(sleepMinutes)}）
                        <button onClick={deleteRecords(index)}>削除</button>
                    </div>
                );
            })}
        </div>
    );
}
export default SleepList;